var _zhRe = /[\u4e00-\u9fff]/;

// Translate a Chinese text string using longest-match decomposition
function _hcTranslate(text, dict) {
  // Try exact match first
  if (dict[text] !== undefined) return dict[text];
  
  // Decompose using longest-match
  var result = '';
  var i = 0;
  while (i < text.length) {
    var matched = false;
    // Try longest match first (up to 80 chars)
    var maxLen = Math.min(text.length - i, 80);
    for (var len = maxLen; len >= 1; len--) {
      var sub = text.substring(i, i + len);
      if (dict[sub] !== undefined) {
        result += dict[sub];
        i += len;
        matched = true;
        break;
      }
    }
    if (!matched) {
      result += text[i];
      i++;
    }
  }
  // Prevent garbled mixed output: if result still contains Chinese characters,
  // it means partial translation occurred — return original to avoid garbage text
  if (_zhRe.test(result)) return text;
  return result;
}

// Store original texts for restore
var _hcOriginals = new Map();
var _hcAttrOriginals = new Map();
var _hcTranslated = false;

// Walk DOM and translate all Chinese text nodes
function _hcTranslateDOM(lang) {
  if (lang === 'zh') {
    // Restore originals
    _hcOriginals.forEach(function(original, node) {
      node.nodeValue = original;
    });
    _hcAttrOriginals.forEach(function(origAttrs, el) {
      origAttrs.forEach(function(val, attr) {
        el.setAttribute(attr, val);
      });
    });
    _hcOriginals.clear();
    _hcAttrOriginals.clear();
    _hcTranslated = false;
    return;
  }
  
  var dict = _hcDicts[lang];
  if (!dict) return;
  
  // If already translated to another language, restore first
  if (_hcTranslated) {
    _hcOriginals.forEach(function(original, node) {
      node.nodeValue = original;
    });
    _hcAttrOriginals.forEach(function(origAttrs, el) {
      origAttrs.forEach(function(val, attr) {
        el.setAttribute(attr, val);
      });
    });
    _hcOriginals.clear();
    _hcAttrOriginals.clear();
  }
  
  // Walk all text nodes
  var walker = document.createTreeWalker(
    document.body,
    NodeFilter.SHOW_TEXT,
    {
      acceptNode: function(node) {
        var parent = node.parentNode;
        if (!parent) return NodeFilter.FILTER_REJECT;
        var tag = parent.tagName;
        if (tag === 'SCRIPT' || tag === 'STYLE' || tag === 'NOSCRIPT') return NodeFilter.FILTER_REJECT;
        // Skip elements with data-i18n (already handled by lang-switcher.js)
        if (parent.hasAttribute && parent.hasAttribute('data-i18n')) return NodeFilter.FILTER_REJECT;
        var text = node.nodeValue;
        if (text && _zhRe.test(text)) return NodeFilter.FILTER_ACCEPT;
        return NodeFilter.FILTER_REJECT;
      }
    }
  );
  
  var textNodes = [];
  while (walker.nextNode()) textNodes.push(walker.currentNode);
  
  textNodes.forEach(function(node) {
    var original = node.nodeValue;
    var translated = _hcTranslate(original.trim(), dict);
    // Preserve leading/trailing whitespace
    var leading = original.match(/^\s*/)[0];
    var trailing = original.match(/\s*$/)[0];
    var newVal = leading + translated + trailing;
    if (newVal !== original) {
      _hcOriginals.set(node, original);
      node.nodeValue = newVal;
    }
  });
  
  // Translate title, alt, aria-label attributes (skip data-i18n elements)
  var attrNames = ['title', 'alt', 'aria-label'];
  attrNames.forEach(function(attr) {
    document.querySelectorAll('[' + attr + ']').forEach(function(el) {
      if (el.hasAttribute('data-i18n')) return;
      var val = el.getAttribute(attr);
      if (val && _zhRe.test(val)) {
        var translated = _hcTranslate(val, dict);
        if (translated !== val) {
          if (!_hcAttrOriginals.has(el)) _hcAttrOriginals.set(el, new Map());
          _hcAttrOriginals.get(el).set(attr, val);
          el.setAttribute(attr, translated);
        }
      }
    });
  });
  
  _hcTranslated = true;
}

// Monkey-patch updatePageContent to also translate hardcoded text
if (typeof updatePageContent === 'function') {
  var _origUpdateHC = updatePageContent;
  window.updatePageContent = function(lang) {
    _origUpdateHC(lang);
    // Small delay to let lang-switcher.js and lang-placeholder.js finish
    setTimeout(function() { _hcTranslateDOM(lang); }, 50);
  };
  updatePageContent = window.updatePageContent;
}

// Also translate on initial load if not Chinese
document.addEventListener('DOMContentLoaded', function() {
  var savedLang = localStorage.getItem('platform_language') || 'zh';
  if (savedLang !== 'zh') {
    setTimeout(function() { _hcTranslateDOM(savedLang); }, 200);
  }
});

// ========== MutationObserver: auto-translate dynamically added Chinese text ==========
var _hcObserver = null;
var _hcObserverTimer = null;

function _hcStartObserver() {
  if (_hcObserver) return;
  var currentLang = (typeof getCurrentLanguage === 'function') ? getCurrentLanguage() : (localStorage.getItem('platform_language') || 'zh');
  if (currentLang === 'zh') return;
  
  var dict = _hcDicts[currentLang];
  if (!dict) return;
  
  _hcObserver = new MutationObserver(function(mutations) {
    // Debounce: batch process mutations
    if (_hcObserverTimer) clearTimeout(_hcObserverTimer);
    _hcObserverTimer = setTimeout(function() {
      var needsTranslate = false;
      for (var i = 0; i < mutations.length; i++) {
        var m = mutations[i];
        // Check added nodes for Chinese text
        if (m.addedNodes && m.addedNodes.length) {
          for (var j = 0; j < m.addedNodes.length; j++) {
            var node = m.addedNodes[j];
            if (node.nodeType === 3 && _zhRe.test(node.nodeValue)) {
              needsTranslate = true; break;
            }
            if (node.nodeType === 1 && node.textContent && _zhRe.test(node.textContent)) {
              needsTranslate = true; break;
            }
          }
        }
        // Check characterData changes
        if (m.type === 'characterData' && m.target.nodeValue && _zhRe.test(m.target.nodeValue)) {
          needsTranslate = true;
        }
        if (needsTranslate) break;
      }
      if (needsTranslate) {
        // Disconnect observer before translating to prevent infinite loop
        _hcStopObserver();
        _hcTranslateDOM(currentLang);
        // Restart observer after a short delay
        setTimeout(_hcStartObserver, 100);
      }
    }, 100);
  });
  
  _hcObserver.observe(document.body, {
    childList: true,
    subtree: true,
    characterData: true
  });
}

function _hcStopObserver() {
  if (_hcObserver) {
    _hcObserver.disconnect();
    _hcObserver = null;
  }
  if (_hcObserverTimer) {
    clearTimeout(_hcObserverTimer);
    _hcObserverTimer = null;
  }
}

// Start observer after DOM ready
document.addEventListener('DOMContentLoaded', function() {
  var savedLang = localStorage.getItem('platform_language') || 'zh';
  if (savedLang !== 'zh') {
    setTimeout(_hcStartObserver, 500);
  }
});

// Re-patch updatePageContent to also manage observer
if (typeof window.updatePageContent === 'function') {
  var _origUpdateHC2 = window.updatePageContent;
  window.updatePageContent = function(lang) {
    _hcStopObserver();
    _origUpdateHC2(lang);
    if (lang !== 'zh') {
      setTimeout(_hcStartObserver, 200);
    }
  };
  updatePageContent = window.updatePageContent;
}

